  if (typeof item.price !== 'number' || item.price <= 0 || item.price > 999999.99 || !Number.isFinite(item.price)) return false;
  // Only allow known fields on items
  const allowedItemFields = new Set(['productId', 'quantity', 'price']);
  for (const key of Object.keys(item)) {
    if (!allowedItemFields.has(key)) return false;
  }
  return true;
