// --- Dead Letter Queue Publisher ---

async function publishToDeadLetterQueue(channel, originalMsg, error) {
  const dlxExchange = process.env.DLX_EXCHANGE || 'events.dlx';
  try {
    const errorInfo = {
      originalContent: originalMsg.content.toString('utf8').substring(0, 1024),
      error: error.message,
      errorType: error.name,
      timestamp: new Date().toISOString(),
      originalRoutingKey: originalMsg.fields.routingKey,
    };
    channel.publish(
      dlxExchange,
      originalMsg.fields.routingKey,
      Buffer.from(JSON.stringify(errorInfo)),
      { persistent: true }
    );
  } catch (dlqError) {
    console.error('[DLQ] Failed to publish to dead letter queue:', dlqError.message);
  }
}

// --- Rate Limiting ---

class MessageRateLimiter {
  constructor(maxPerSecond = 100) {
    this.maxPerSecond = maxPerSecond;
    this.count = 0;
    this.resetInterval = setInterval(() => {
      this.count = 0;
    }, 1000);
  }

  tryConsume() {
    if (this.count >= this.maxPerSecond) {
      return false;
    }
    this.count++;
    return true;
  }

  destroy() {
    clearInterval(this.resetInterval);
  }
}

// --- Main Service ---

async function startService() {
  const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
  const QUEUE_NAME = process.env.QUEUE_NAME || 'events.processing';
  const PREFETCH_COUNT = parseInt(process.env.PREFETCH_COUNT, 10) || 10;
  const RATE_LIMIT = parseInt(process.env.RATE_LIMIT, 10) || 100;

  const rateLimiter = new MessageRateLimiter(RATE_LIMIT);

  let connection;
  let channel;

  async function connect() {
    connection = await amqplib.connect(RABBITMQ_URL, {
      heartbeat: 30,
    });

    connection.on('error', (err) => {
      console.error('[AMQP] Connection error:', err.message);
    });

    connection.on('close', () => {
      console.warn('[AMQP] Connection closed. Reconnecting in 5s...');
      setTimeout(connect, 5000);
    });

    channel = await connection.createChannel();

    // Set prefetch to limit concurrent processing
    await channel.prefetch(PREFETCH_COUNT);

    // Assert queue and dead letter exchange
    const dlxExchange = process.env.DLX_EXCHANGE || 'events.dlx';
    const dlqQueue = `${QUEUE_NAME}.dlq`;

    await channel.assertExchange(dlxExchange, 'topic', { durable: true });
    await channel.assertQueue(dlqQueue, { durable: true });
    await channel.bindQueue(dlqQueue, dlxExchange, '#');

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': dlxExchange,
        'x-message-ttl': 86400000, // 24 hours
      },
    });

    console.log(`[AMQP] Connected. Consuming from queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      // Rate limiting check
      if (!rateLimiter.tryConsume()) {
        // Requeue the message if rate limited
        channel.nack(msg, false, true);
        return;
      }

      try {
        // Validate message properties
        if (msg.properties && msg.properties.contentType &&
            msg.properties.contentType !== 'application/json') {
          throw new ValidationError(`Unsupported content type: ${msg.properties.contentType}`);
        }

        // Parse and validate the message
        const validatedMessage = parseAndValidateMessage(msg.content);

        // Look up handler
        const handler = messageHandlers[validatedMessage.type];
        if (!handler) {
          // This shouldn't happen due to validation, but defense in depth
          throw new ValidationError(`No handler for message type: ${validatedMessage.type}`);
        }

        // Execute the handler
        await handler(validatedMessage.payload, validatedMessage.correlationId);

        // Acknowledge successful processing
        channel.ack(msg);
      } catch (error) {
        if (error instanceof ValidationError) {
          // Validation errors: reject without requeue, send to DLQ
          console.error(`[VALIDATION] Rejected message: ${error.message}`);
          await publishToDeadLetterQueue(channel, msg, error);
          channel.nack(msg, false, false); // Don't requeue invalid messages
        } else {
          // Processing errors: could be transient, requeue with limit
          const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;
          const maxRetries = 3;

          if (retryCount >= maxRetries) {
            console.error(`[PROCESSING] Max retries exceeded. Sending to DLQ: ${error.message}`);
            await publishToDeadLetterQueue(channel, msg, error);
            channel.nack(msg, false, false);
          } else {
            console.warn(`[PROCESSING] Error (retry ${retryCount + 1}/${maxRetries}): ${error.message}`);
            // Nack and requeue
            channel.nack(msg, false, true);
          }
        }
      }
    }, {
      noAck: false, // Manual acknowledgment
    });
  }

  // Graceful shutdown
  async function shutdown(signal) {
    console.log(`[SERVICE] Received ${signal}. Shutting down gracefully...`);
    rateLimiter.destroy();

    try {
      if (channel) {
        await channel.close();
      }
      if (connection) {
        await connection.close();
      }
      await pool.end();
      console.log('[SERVICE] Shutdown complete.');
      process.exit(0);
    } catch (err) {
      console.error('[SERVICE] Error during shutdown:', err.message);
      process.exit(1);
    }
  }

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));

  // Handle uncaught errors
  process.on('uncaughtException', (err) => {
    console.error('[FATAL] Uncaught exception:', err.message);
    shutdown('uncaughtException');
  });

  process.on('unhandledRejection', (reason) => {
    console.error('[FATAL] Unhandled rejection:', reason);
    shutdown('unhandledRejection');
  });

  await connect();
}

startService().catch((err) => {
  console.error('[STARTUP] Failed to start service:', err.message);
  process.exit(1);
});

